const output = ($json.output || $json.text || '').toString().trim();

let reply = output || 'Не смог сформировать ответ. Напиши ещё раз, пожалуйста.';

// Telegram limit is 4096 characters. Keep a safe margin.
if (reply.length > 3900) {
  reply = reply.slice(0, 3900) + '\n\n…ответ был слишком длинный, поэтому я сократил его.';
}

return [
  {
    json: {
      chatId: $('Prepare Telegram Message2').first().json.chatId,
      reply
    }
  }
];

const msg = $json.message || $json.edited_message || {};
const chatId = msg.chat?.id;

if (!chatId) {
  throw new Error('Telegram chat id not found. Check Telegram Trigger output.');
}

const rawText = (msg.text || msg.caption || '').trim();

return [
  {
    json: {
      chatId,
      userId: msg.from?.id || null,
      username: msg.from?.username || '',
      firstName: msg.from?.first_name || '',
      messageId: msg.message_id || null,
      userText: rawText || 'Пользователь отправил не текстовое сообщение. Вежливо попроси его отправить текст.'
    }
  }
];

const weather = $('Get Weather1').first().json;
const events = ($('Aggregate Events').first().json.eventsData) || [];
let gmail = [];
try { gmail = ($('Aggregate Emails').first().json.emailsData) || []; } catch (e) { gmail = []; }
let sheets = [];
try { sheets = $('Get Projects Sheet1').all().map(i => i.json); } catch (e) { sheets = []; }

const temp = Math.round(weather.current?.temperature_2m ?? 0);
const sunrise = (weather.daily?.sunrise?.[0] || '').split('T')[1] || '--:--';
const sunset = (weather.daily?.sunset?.[0] || '').split('T')[1] || '--:--';

const now = new Date();
const dateStr = now.toLocaleDateString('uz-UZ', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric', timeZone: 'Asia/Tashkent' });
const timeStr = now.toLocaleTimeString('uz-UZ', { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Tashkent' });

let calendarBlock = events.length
  ? events.map(e => {
      const start = (e.start?.dateTime || e.start?.date || '').slice(11,16) || 'kun bo\u2018yi';
      return `\ud83d\udfe2 ${start} \u2014 ${e.summary || 'Nomsiz tadbir'}${e.location ? `\n\ud83d\udccd ${e.location}` : ''}`;
    }).join('\n')
  : 'Bugun rejalashtirilgan tadbir yo\u2018q \u2705';

const gmailCount = gmail.length;
const gmailImportant = gmail.slice(0,3).map(m => {
  const from = m.payload?.headers?.find(h => h.name === 'From')?.value || '';
  return from.split('<')[0].trim();
}).filter(Boolean).join(', ');

let projectsBlock = sheets.length
  ? sheets.map(p => {
      const status = p.Status || '\u26aa';
      const prog = p.Progress || '-';
      const priority = p.Priority ? ` (${p.Priority})` : '';
      const deadline = p.Deadline && p.Deadline !== '-' ? `\n   \ud83d\udcc6 Muddat: ${p.Deadline}` : '';
      const nextTask = p['Next Task'] && p['Next Task'] !== '-' ? `\n   \u25b6\ufe0f Keyingi: ${p['Next Task']}` : '';
      return `${status} ${p.Project}${priority} \u2014 ${prog}${deadline}${nextTask}`;
    }).join('\n')
  : 'Loyihalar ro\u2018yxati bo\u2018sh (Google Sheets\u2019ni to\u2018ldiring)';

const overdueOrHigh = sheets.filter(p => (p.Priority || '').toLowerCase().includes('high')).map(p => p.Project);

const summaryForAI = `Bugun ${events.length} ta tadbir, ${gmailCount} ta o'qilmagan email. Loyihalar: ${sheets.length ? sheets.map(p => `${p.Project} (${p.Progress}, ${p.Priority || 'priority yo\u2018q'}, keyingi vazifa: ${p['Next Task'] || 'yo\u2018q'})`).join('; ') : 'yo\u2018q'}. Yuqori muhimlikdagi loyihalar: ${overdueOrHigh.length ? overdueOrHigh.join(', ') : 'yo\u2018q'}.`;

return [{
  json: {
    dateStr, timeStr, temp, sunrise, sunset,
    calendarBlock, gmailCount, gmailImportant, projectsBlock,
    summaryForAI
  }
}];

const base = $('Build Digest Base1').first().json;
const aiOutput = ($json.output || $json.text || '').trim();

const message = `🌅 Assalomu alaykum, Asadulla!
Bugun: ${base.dateStr}
🕗 Hozir: ${base.timeStr}
📍 Toshkent
🌤 Havo: +${base.temp}°C
🌅 Quyosh chiqishi: ${base.sunrise}
🌇 Quyosh botishi: ${base.sunset}
━━━━━━━━━━━━━━━━━━━━━━━━
📅 BUGUNGI REJALAR
${base.calendarBlock}
━━━━━━━━━━━━━━━━━━━━━━━━
📧 EMAIL
📥 Yangi: ${base.gmailCount} ta${base.gmailImportant ? `
⭐ ${base.gmailImportant}` : ''}
━━━━━━━━━━━━━━━━━━━━━━━━
💻 LOYIHALAR
${base.projectsBlock}
━━━━━━━━━━━━━━━━━━━━━━━━
${aiOutput}`;

let finalMessage = message;
if (finalMessage.length > 3900) {
  finalMessage = finalMessage.slice(0, 3900) + '

…xabar juda uzun edi, qisqartirildi.';
}

return [{ json: { chatId: '1211791131', reply: finalMessage } }];
